#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    std::string SName;
    rfl::Field<"Sex", int> sex = 1;
    std::optional<std::string> Birthday;
    std::optional<int> Major;
    rfl::Field<"Scorses", float> scorses = 0.0f;
    std::optional<std::string> Remark;
  };

  struct Course {
    sqlgen::PrimaryKey<int> CID;
    std::string CName;
    rfl::Field<"Term", int> term = 1;
    std::optional<int> CTime;
    rfl::Field<"Credit", float> credit = 0.0f;
  };

  struct Score {
    sqlgen::ForeignKey<std::string, Student> SNo;
    sqlgen::ForeignKey<int, Course> CID;
    std::optional<float> Score;
  };

  void design_eas_database() {
    // Remove existing database file if it exists
    std::filesystem::remove("test_db.sqlite");

    // Create database connection
    auto db = sqlgen::Database<sqlgen::sqlite::Connection>("test_db.sqlite");

    // Create tables
    db.create_table<Student>();
    db.create_table<Course>();
    db.create_table<Score>();
  }

}
```

Key points about this implementation:

1. **Student struct**:
   - `SNo` is marked as `sqlgen::PrimaryKey<std::string>` for the varchar(10) primary key
   - `Sex` uses `rfl::Field` with default value of 1
   - `Scorses` uses `rfl::Field` with default value of 0.0f
   - Nullable fields use `std::optional`

2. **Course struct**:
   - `CID` is `sqlgen::PrimaryKey<int>` for auto-increment primary key
   - `Term` and `Credit` use `rfl::Field` with default values
   - `CTime` uses `std::optional` for nullable field

3. **Score struct**:
   - `SNo` and `CID` use `sqlgen::ForeignKey` to reference the Student and Course tables
   - The composite primary key is automatically handled by sqlgen when both fields are foreign keys
   - `Score` uses `std::optional` for nullable field

4. **design_eas_database function**:
   - Removes existing database file to start fresh
   - Creates SQLite database connection
   - Creates all three tables using `db.create_table<>()`

The sqlgen library automatically handles the foreign key relationships and composite primary key based on the field annotations. The `rfl::Field` annotations are used to specify default values for fields that have them in the schema.

