#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database and create tables
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(create_table<Course> | if_not_exists)
    .and_then(create_table<Enrollment> | if_not_exists);

  if (!result) {
    // Return empty vector if connection/table creation fails
    return {};
  }

  // Query enrollment statistics using LEFT JOIN and GROUP BY
  auto conn = result.value();

  // Use raw SQL query to get the required statistics
  // The sqlgen library doesn't have built-in support for complex GROUP BY with aggregates
  // so we'll use a raw query approach
  std::vector<CourseStats> stats;

  // Execute the SQL query directly
  auto query_result = conn.execute(
    "SELECT c.title, COUNT(e.enrollment_id) as student_count, AVG(e.grade) as avg_grade "
    "FROM Course c "
    "LEFT JOIN Enrollment e ON c.course_id = e.course_id "
    "GROUP BY c.course_id, c.title"
  );

  if (!query_result) {
    return {};
  }

  // Process the result set
  auto stmt = query_result.value();
  while (stmt.step()) {
    CourseStats course_stat;
    course_stat.title = stmt.get<std::string>(0);
    course_stat.student_count = stmt.get<int>(1);

    // Handle NULL average grade
    if (stmt.column_type(2) == SQLITE_NULL) {
      course_stat.avg_grade = std::nullopt;
    } else {
      course_stat.avg_grade = stmt.get<double>(2);
    }

    stats.push_back(course_stat);
  }

  return stats;
}

}  // namespace query_course_enrollment_stats

