 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  conn.create_table<Customer>();
  conn.create_table<Product>();
  conn.create_table<Order>();
  conn.create_table<OrderItem>();

  // Execute the query using sqlgen's query builder
  using namespace sqlgen::literals;

  auto results = conn.query<PurchaseHistory>(
    "SELECT p.name as product_name, o.order_date, oi.quantity "
    "FROM Customer c "
    "JOIN \"Order\" o ON c.customer_id = o.customer_id "
    "JOIN OrderItem oi ON o.order_id = oi.order_id "
    "JOIN Product p ON oi.product_id = p.product_id "
    "WHERE c.customer_id = ? "
    "ORDER BY o.order_date DESC",
    customer_id
  );

  // Convert the results range to a vector and return
