However, I notice there's an issue with the above approach. The `ProductSalesReport` struct is defined as a view, but we need to actually perform the join and aggregation. Let me provide a more complete solution that properly handles the join and grouping:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    sqlgen::sqlite::Database db("test_db.sqlite");

    // First, let's create the view if it doesn't exist
    db.execute(R"(
        CREATE VIEW IF NOT EXISTS ProductSalesReport AS
        SELECT p.category, SUM(s.quantity) as total_qty, SUM(s.amount) as total_amt
        FROM Product p
        INNER JOIN Sale s ON p.product_id = s.product_id
        GROUP BY p.category
    )");

    // Query the view with the HAVING condition
    auto query = sqlgen::read<std::vector<ProductSalesReport>> |
                 where("total_amt"_c > 5000);

    // Execute the query
    auto view_results = db | query;

    // Convert to CategoryReport format
    std::vector<CategoryReport> results;
    results.reserve(view_results.size());

    for (const auto& view_result : view_results) {
        results.push_back(CategoryReport{
            .category = view_result.category,
            .total_qty = view_result.total_qty,
            .total_amt = view_result.total_amt
        });
    }

    return results;
}

}  // namespace query_product_sales_report
```

