Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // Start with base SELECT query
    auto query = select<Book>;

    // Build conditions dynamically based on provided filters
    if (filters.title_keyword || filters.min_year || filters.genre || filters.max_price) {
        auto condition = sqlgen::condition(true);

        if (filters.title_keyword) {
            condition = condition && ("title"_c.like("%" + *filters.title_keyword + "%"));
        }

        if (filters.min_year) {
            condition = condition && ("year"_c >= *filters.min_year);
        }

        if (filters.genre) {
            condition = condition && ("genre"_c == *filters.genre);
        }

        if (filters.max_price) {
            condition = condition && ("price"_c <= *filters.max_price);
        }

        query = query | where(condition);
    }

    // Execute the query and return results
    return conn.and_then(query).and_then(read<std::vector<Book>>).value();
}

}  // namespace query_search_books_by_criteria
```

This implementation:

1. **Connects to the database** using `sqlgen::sqlite::connect("test_db.sqlite")`
2. **Starts with a base SELECT query** using `select<Book>`
3. **Dynamically builds WHERE clauses** based on the provided filters:
   - Uses `LIKE` with wildcards for title keyword search
   - Uses `>=` for minimum year filter
   - Uses `==` for genre filter (exact match)
   - Uses `<=` for maximum price filter
4. **Combines conditions** using the `&&` operator, only adding clauses for non-null parameters
5. **Executes the query** and returns the results as a vector of `Book` objects

The code follows the patterns shown in the provided code fragments, using the `sqlgen` library's fluent interface for building SQL queries in a type-safe manner.

