```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }

  auto conn = conn_result.value();

  // Start transaction
  auto begin_result = conn.exec("BEGIN TRANSACTION");
  if (!begin_result) {
    return false; // Failed to start transaction
  }

  try {
    // Check if sender has sufficient funds and deduct
    auto deduct_result = conn.exec(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    if (!deduct_result || deduct_result.value() != 1) {
      // Either the update failed or no rows were updated (insufficient funds)
      conn.exec("ROLLBACK");
      return false;
    }

    // Add funds to receiver
    auto add_result = conn.exec(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    if (!add_result || add_result.value() != 1) {
      // Update failed or account doesn't exist
      conn.exec("ROLLBACK");
      return false;
    }

    // Commit transaction
    auto commit_result = conn.exec("COMMIT");
    if (!commit_result) {
      conn.exec("ROLLBACK");
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn.exec("ROLLBACK");
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

