Here's the complete implementation of the `update_order_status` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
   // Connect to the SQLite database
   auto db = sqlgen::sqlite::database::open("test_db.sqlite");

   // First update: pending orders older than 7 days to expired
   auto update_expired = sqlgen::update<Order>()
       .set(&Order::status, "expired")
       .where(sqlgen::eq(&Order::status, "pending") && 
              sqlgen::lt(&Order::order_date, sqlgen::date_sub(sqlgen::now(), 7, "days")));

   // Second update: shipped orders to delivered (simulating delivery confirmation)
   auto update_delivered = sqlgen::update<Order>()
       .set(&Order::status, "delivered")
       .where(sqlgen::eq(&Order::status, "shipped"));

   // Execute both updates and return total rows affected
   int total_affected = 0;
   total_affected += db.execute(update_expired);
   total_affected += db.execute(update_delivered);

   return total_affected;
}

} // namespace update_order_status
```

This implementation:

1. **Connects to the database** using `sqlgen::sqlite::database::open("test_db.sqlite")`

2. **Updates pending orders older than 7 days** using SQLite date functions through `sqlgen::date_sub(sqlgen::now(), 7, "days")`

3. **Updates shipped orders to delivered** to simulate delivery confirmation

4. **Returns the total number of rows affected** by summing the results of both UPDATE operations

The code uses the `sqlgen` library's type-safe query building syntax with methods like:
- `.set()` to specify column updates
- `.where()` to define conditions
- `sqlgen::eq()` for equality comparisons
- `sqlgen::lt()` for less-than comparisons
- `sqlgen::date_sub()` for date arithmetic

This approach ensures type safety while generating the appropriate SQL UPDATE statements with WHERE clauses as specified in the requirements.

