TEST(sqlite, upsert_user_profile) {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<UserProfile>(conn);
  create_table<UserProfile>(conn);

  UserProfile u1{.user_id = 1, .bio = "first", .avatar_url = "a1.png"};
