  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  try {
    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn) {
      return false;
    }

    // Define the view creation query using sqlgen's query builder
    auto view_query = select(
        column<"name">(&Product::name).as("product_name"),
        sum(column<"quantity">(&Sale::quantity)).as("total_quantity"),
        sum(column<"amount">(&Sale::amount)).as("total_revenue")
    ).from<Sale>()
     .join<Product>().on(column<"product_id">(&Sale::product_id) == column<"product_id">(&Product::product_id))
     .group_by(column<"name">(&Product::name));

    // Create the view using create_as with if_not_exists
    auto result = conn
                  .and_then(create_as<SalesSummary>(view_query) | if_not_exists)
                  .and_then([](auto) { return sqlgen::result<void>{}; });

    return result.has_value();
  } catch (const std::exception& e) {
    // Log error if needed
    return false;
  }
}

}  // namespace schema_create_view_sales_summary
