#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace generate_sql_dry_run {

struct A {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct B {
  sqlgen::PrimaryKey<int> id;
  int a_id;
  double score;
};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build complex query with joins, where, order_by, limit
  const auto query = sqlgen::read<std::vector<std::tuple<A, B>>> |
                     join<B>("A.id"_c == "B.a_id"_c) |
                     where("B.score"_c > 10.0 and "A.name"_c.like("%x%")) |
                     order_by("B.score"_c.desc()) |
                     limit(100);

  // Generate SQL string for SQLite (dry run)
  std::string sql = sqlgen::sqlite::to_sql(query);

  // Verify generated SQL contains expected clauses
  // Note: This is for debugging/demonstration purposes
  bool contains_expected_clauses = 
      sql.find("SELECT") != std::string::npos &&
      sql.find("FROM") != std::string::npos &&
      sql.find("JOIN") != std::string::npos &&
      sql.find("WHERE") != std::string::npos &&
      sql.find("ORDER BY") != std::string::npos &&
      sql.find("LIMIT") != std::string::npos;

  // For demonstration, you could add assertions or logging here
  // assert(contains_expected_clauses && "Generated SQL missing expected clauses");

  return sql;
}

}  // namespace generate_sql_dry_run
