```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to SQLite database
  Connection conn("test_db.sqlite");

  // Create temporary Event table
  auto create_table = CreateTable<Event>{}.temporary().if_not_exists();
  conn.execute(to_sql(create_table));

  // Insert events into the table
  for (const auto& event : events) {
    auto insert = Insert<Event>{event};
    conn.execute(to_sql(insert));
  }

  // Execute temporal analysis query
  std::vector<TemporalAnalysis> results;

  // SQLite uses different function names than the reference SQL
  // Using SQLite's strftime and julianday functions for temporal analysis
  const char* query_sql = R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
      CASE 
        WHEN end_time IS NOT NULL THEN julianday(end_time) - julianday(start_time)
        ELSE NULL 
      END as duration_days
    FROM Event
    WHERE end_time IS NOT NULL;
  )";

  conn.query(query_sql, [&results](const TemporalAnalysis& row) {
    results.push_back(row);
  });

  return results;
}

}  // namespace analyze_temporal_data
```

This implementation:

1. **Connects to SQLite database** using `sqlgen::sqlite::Connection`
2. **Creates a temporary table** using `sqlgen::CreateTable` with the Event structure
3. **Inserts all events** using `sqlgen::Insert` statements
4. **Executes a temporal analysis query** that uses SQLite-specific functions:
   - `strftime()` for extracting date/time components
   - `julianday()` for calculating day differences
   - `%s` format for Unix epoch conversion
5. **Maps results directly** to the `TemporalAnalysis` struct using SQLite's query callback mechanism

The query uses SQLite's native date/time functions since the reference SQL functions (`DAY()`, `MONTH()`, `YEAR()`, `DAYS_BETWEEN()`, etc.) are not available in SQLite. The `julianday()` function provides precise day difference calculations including fractional days for time components.

