```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user_id1;
  int user_id2;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendsResult {
  std::string username1;
  std::string username2;
  int mutual_friends_count;
};

struct UserFriendCount {
  int user_id;
  std::string username;
  int friend_count;
};

struct FriendOfFriend {
  std::string user1_name;
  std::string mutual_friend_name;
  std::string user2_name;
};

struct SameCityNonFriends {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Create in-memory SQLite database
  const auto credentials = sqlite::Credentials{":memory:"};
  auto db = sqlite::Database{credentials};

  // Create User table
  db.execute(CreateTable<User>{});

  // Create Friendship table
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS Friendship (
      user_id1 INTEGER NOT NULL,
      user_id2 INTEGER NOT NULL,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    )
  )"_sql);

  // Insert users
  if (!users.empty()) {
    db.execute(Insert<User>{users});
  }

  // Insert friendships
  if (!friendships.empty()) {
    // Since Friendship struct doesn't match the exact table structure, we'll use raw SQL
    for (const auto& friendship : friendships) {
      db.execute("INSERT INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)"_sql,
                 friendship.user_id1, friendship.user_id2, friendship.friendship_date);
    }
  }

  std::vector<FriendConnection> results;

  // 1. Find mutual friends using SELF-JOIN
  auto mutual_friends = db.fetch(R"(
    SELECT u1.username as user1, u2.username as user2, COUNT(f1.user_id2) as mutual_count
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
      )
    GROUP BY u1.user_id, u2.user_id
    HAVING COUNT(f1.user_id2) > 0
  )"_sql);

  for (const auto& row : mutual_friends) {
    results.push_back(FriendConnection{
      .user1_name = std::get<0>(row),
      .user2_name = std::get<1>(row)
    });
  }

  // 2. Find users with more than average number of friends using nested query
  auto popular_users = db.fetch(R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1) as subq
    )
    ORDER BY friend_count DESC
  )"_sql);

  for (const auto& row : popular_users) {
    results.push_back(FriendConnection{
      .user1_name = std::get<1>(row) + " (Highly Connected)",
      .user2_name = "Friend Count: " + std::to_string(std::get<2>(row))
    });
  }

  // 3. Find friend-of-friend relationships
  auto friend_of_friend = db.fetch(R"(
    SELECT DISTINCT u1.username, u2.username
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id != u2.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
      )
  )"_sql);

  for (const auto& row : friend_of_friend) {
    results.push_back(FriendConnection{
      .user1_name = std::get<0>(row) + " (Friend-of-Friend)",
      .user2_name = std::get<1>(row)
    });
  }

  // 4. Count friends per user and identify most connected users
  auto friend_counts = db.fetch(R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
    LIMIT 5
  )"_sql);

  for (const auto& row : friend_counts) {
    results.push_back(FriendConnection{
      .user1_name = "Most Connected: " + std::get<1>(row),
      .user2_name = "Friends: " + std::to_string(std::get<2>(row))
    });
  }

  // 5. Find users in the same city who are not yet friends (if city field exists)
  try {
    auto same_city_non_friends = db.fetch(R"(
      SELECT u1.username, u2.username, u1.city
      FROM User u1
      INNER JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
      WHERE u1.city IS NOT NULL 
        AND u1.city != ''
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f 
          WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
             OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
        )
    )"_sql);

    for (const auto& row : same_city_non_friends) {
      results.push_back(FriendConnection{
        .user1_name = std::get<0>(row) + " (Same City)",
        .user2_name = std::get<1>(row) + " in " + std::get<2>(row)
      });
    }
  } catch (const std::exception& e) {
    // If city column doesn't exist or other errors, skip this query
  }

  return results;
}

}  // namespace analyze_social_network
