```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace join_orders_customers_payments {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct Payment {
  sqlgen::PrimaryKey<int> payment_id;
  int order_id;
  double amount;
};

struct Consolidated {
  sqlgen::PrimaryKey<int> order_id;
  std::string customer_name;
  double amount;
};

/**
 * description: join_orders_customers_payments.
 * This function demonstrates how to join three tables (Orders, Customers, and Payments)
 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  // Connect to the SQLite database
  sqlgen::sqlite::Connection connection("test_db.sqlite");

  // Build the join query using sqlgen's query builder
  auto query = sqlgen::query<Consolidated>()
    .select(
      sqlgen::column<&Order::order_id>(),
      sqlgen::column<&Customer::name>().as("customer_name"),
      sqlgen::column<&Payment::amount>()
    )
    .from<Order>()
    .inner_join<Customer>().on(
      sqlgen::column<&Order::customer_id>() == sqlgen::column<&Customer::customer_id>()
    )
    .inner_join<Payment>().on(
      sqlgen::column<&Order::order_id>() == sqlgen::column<&Payment::order_id>()
    )
    .order_by(sqlgen::column<&Payment::amount>(), sqlgen::Order::DESC);

  // Execute the query and return the results
  return query.exec(connection);
}

}  // namespace join_orders_customers_payments
