```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace column_is_null_checks {

struct Profile {
  sqlgen::PrimaryKey<int> profile_id;
  std::string display_name;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

struct Result {
  int profile_id;
  std::string display_name;
};

std::vector<Result> column_is_null_checks() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Filter rows where bio is NULL and avatar_url is NOT NULL
  auto results = conn | sqlgen::read<std::vector<Profile>> 
                      | where("bio"_c.is_null() && "avatar_url"_c.is_not_null())
                      | select(&Profile::profile_id, &Profile::display_name);

  std::vector<Result> final_results;
  for (const auto& result : results) {
    final_results.push_back(Result{
        static_cast<int>(std::get<0>(result)),
        std::get<1>(result)
    });
  }

  return final_results;
}

}  // namespace column_is_null_checks
```

