Looking at the code fragments and the requirements, I need to implement a FULL JOIN between suppliers and products using the `sqlgen` library. Since SQLite doesn't natively support FULL JOIN, I'll need to simulate it using a combination of LEFT JOIN and UNION ALL.

Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Since SQLite doesn't support FULL JOIN natively, we simulate it with LEFT JOIN and UNION ALL
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([](auto conn) {
      // First part: Suppliers with their products (LEFT JOIN)
      auto left_join = select("s.name"_c.as("supplier_name"), 
                             "p.name"_c.as("product_name"))
                      .from<Supplier>("s")
                      .left_join<Product>("p").on("s.supplier_id"_c == "p.supplier_id"_c);

      // Second part: Products without suppliers (using anti-join pattern)
      auto products_without_suppliers = select("''"_c.as("supplier_name"), 
                                              "p.name"_c.as("product_name"))
                                       .from<Product>("p")
                                       .where(not_exists(select(1_c)
                                               .from<Supplier>("s")
                                               .where("s.supplier_id"_c == "p.supplier_id"_c)));

      // Combine using UNION ALL to simulate FULL JOIN
      auto full_join_query = left_join.union_all(products_without_suppliers);

      return sqlgen::read<std::vector<SupProd>>(conn, full_join_query);
    });

  return result.value_or(std::vector<SupProd>{});
}

}  // namespace full_join_suppliers_products
```

