struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([](auto conn) {
      // Simulate FULL JOIN using UNION of LEFT JOIN and RIGHT JOIN
      // Since SQLite doesn't have RIGHT JOIN, we reverse the tables for the second part

      // Part 1: LEFT JOIN (all suppliers with their products)
      auto left_part = select("s.name"_c.as("supplier_name"), 
                             "p.name"_c.as("product_name"))
                      .from<Supplier>("s")
                      .left_join<Product>("p").on("s.supplier_id"_c == "p.supplier_id"_c);

      // Part 2: RIGHT JOIN equivalent (products without matching suppliers)
      // We achieve this by doing a LEFT JOIN with tables reversed and filtering
      auto right_part = select("s.name"_c.as("supplier_name"), 
                              "p.name"_c.as("product_name"))
                       .from<Product>("p")
                       .left_join<Supplier>("s").on("p.supplier_id"_c == "s.supplier_id"_c)
                       .where("s.supplier_id"_c.is_null());

      // Combine using UNION to get FULL JOIN result
      auto full_join_query = left_part.union_all(right_part);

      return sqlgen::read<std::vector<SupProd>>(conn, full_join_query);
    });

  return result.value_or(std::vector<SupProd>{});
}

}  // namespace full_join_suppliers_products
