namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to SQLite database
  auto db = sqlite::connect("test_db.sqlite");

  // Create temporary tables
  db.and_then(create_table<Department> | if_not_exists);
  db.and_then(create_table<Employee> | if_not_exists);

  // Insert department data
  if (!depts.empty()) {
    db.and_then(insert_range(depts));
  }

  // Insert employee data  
  if (!emps.empty()) {
    db.and_then(insert_range(emps));
  }

  // INNER JOIN: Get employees with assigned departments
  auto inner_join_query = 
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d "
    "INNER JOIN Employee e ON d.department_id = e.department_id"_sql;

  auto inner_results = db.and_then(read<std::vector<JoinResult>>(inner_join_query));
  if (inner_results) {
    analysis.inner_join_results = std::move(*inner_results);
  }

  // LEFT JOIN: Include all employees (even without departments)
  auto left_join_query = 
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e "
    "LEFT JOIN Department d ON e.department_id = d.department_id"_sql;

  auto left_results = db.and_then(read<std::vector<JoinResult>>(left_join_query));
  if (left_results) {
    analysis.left_join_results = std::move(*left_results);
  }

  // RIGHT JOIN: Include all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we emulate it with LEFT JOIN
  auto right_join_query = 
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d "
    "LEFT JOIN Employee e ON d.department_id = e.department_id "
    "WHERE e.department_id IS NULL "
    "UNION ALL "
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e "
    "RIGHT JOIN Department d ON e.department_id = d.department_id "
    "WHERE e.department_id IS NOT NULL"_sql;

  auto right_results = db.and_then(read<std::vector<JoinResult>>(right_join_query));
  if (right_results) {
    analysis.right_join_results = std::move(*right_results);
  }

  // FULL JOIN: Include all employees and all departments
  // SQLite doesn't support FULL JOIN directly, so we emulate it with UNION of LEFT and RIGHT
  auto full_join_query = 
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e "
    "LEFT JOIN Department d ON e.department_id = d.department_id "
    "UNION ALL "
    "SELECT d.department_name, NULL as first_name, NULL as last_name, NULL as salary "
    "FROM Department d "
    "WHERE d.department_id NOT IN (SELECT department_id FROM Employee WHERE department_id IS NOT NULL)"_sql;

  auto full_results = db.and_then(read<std::vector<JoinResult>>(full_join_query));
  if (full_results) {
    analysis.full_join_results = std::move(*full_results);
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to SQLite database** using `sqlgen::sqlite::connect("test_db.sqlite")`
2. **Creates tables** for Department and Employee using `create_table` with `if_not_exists` option
3. **Inserts data** from the input vectors using `insert_range`
4. **Performs four types of joins**:
   - **INNER JOIN**: Gets only employees with assigned departments
   - **LEFT JOIN**: Includes all employees, even those without departments
   - **RIGHT JOIN**: Includes all departments, even those without employees (emulated since SQLite doesn't support RIGHT JOIN natively)
   - **FULL JOIN**: Includes all records from both tables (emulated using UNION)
5. **Stores results** in the `JoinAnalysis` struct with proper optional field handling
6. **Returns comprehensive analysis** containing all join results

The code handles the optional nature of fields in join results (where some fields might be NULL) using `std::optional`, and follows the sqlgen library patterns demonstrated in the provided code fragments.

